import {cloneConfig} from './defaults.js';
export const PRESETS={'Standard RPG engraving':{},'Soft engraving':{tone:{contrast:.9,gamma:1.1},hatching:{scale:1.4}},'Dense crosshatch':{hatching:{scale:.65,cross:true}},'Comic high contrast':{tone:{contrast:1.5,gamma:.85},posterize:{levels:4,thresholds:[235,150,80]}},'Medieval etching':{tone:{contrast:1.2},hatching:{scale:.8,cross:true},border:{strokeWidth:1.6}},'Laser safe low detail':{image:{maxDimension:800},details:{enabled:false},hatching:{scale:1.8},edges:{minToneJump:3}},'Stress test / maximum detail':{image:{maxDimension:1500},hatching:{scale:.45,cross:true},details:{maxNoise:20000}}};
export function applyPreset(name){const c=cloneConfig(),p=PRESETS[name]||{};Object.assign(c.tone,p.tone||{});Object.assign(c.posterize,p.posterize||{});Object.assign(c.image,p.image||{});Object.assign(c.details,p.details||{});Object.assign(c.edges,p.edges||{});Object.assign(c.border,p.border||{});if(p.hatching?.scale)c.hatching.levels.forEach(x=>{if(x)x.spacing*=p.hatching.scale});if(p.hatching?.cross)c.hatching.levels.forEach(x=>{if(x&&!x.secondAngle)x.secondAngle=x.angle+90});return c}
